SUPPORTED_LANGUAGES = {
    "en": "English",
    "de": "Deutsch",
    "fr": "Français",
    "es": "Español",
    "nl": "Nederlands",
}

def get_translator(lang: str):
    """Return a translation function for the given language code."""
    table = TRANSLATIONS.get(lang, {})
    def _(text: str) -> str:
        return table.get(text, text)
    return _
